import{_ as e,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as l,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Safety/user-rate-limits.md","filePath":"hi/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),r={name:"hi/Safety/user-rate-limits.md"};function o(p,t,n,u,c,m){return l(),s("div",null,[...t[0]||(t[0]=[d('<h1 id="user-rate-limits" tabindex="-1">User Rate Limits <a class="header-anchor" href="#user-rate-limits" aria-label="Permalink to &quot;User Rate Limits&quot;">​</a></h1><p>User rate limits यह control करते हैं कि regular users या visitors homepage से कितनी बार files upload कर सकते हैं। इससे public upload pages के misuse को रोकने में मदद मिलती है।</p><p>यह feature केवल homepage uploads पर लागू होता है। Admin uploads और API Tokens से किए गए uploads पर user rate limits लागू नहीं होते।</p><h2 id="कहाँ-सेट-करें" tabindex="-1">कहाँ सेट करें <a class="header-anchor" href="#कहाँ-सेट-करें" aria-label="Permalink to &quot;कहाँ सेट करें&quot;">​</a></h2><p>Admin panel खोलें, फिर यहाँ जाएँ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+e+'" alt="User rate limit settings" loading="lazy"></p><h2 id="rate-limits-enable-करना" tabindex="-1">Rate Limits Enable करना <a class="header-anchor" href="#rate-limits-enable-करना" aria-label="Permalink to &quot;Rate Limits Enable करना&quot;">​</a></h2><p><code>Enable Rate Limits</code> चालू करने के बाद ImgBed uploader IP address के आधार पर recent uploads track करता है।</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>कितने समय पीछे तक upload records count होंगे।</td></tr><tr><td>Max file count</td><td>20</td><td>Detection window में allowed maximum file count।</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>एक file का maximum size।</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>Detection window में maximum total upload size।</td></tr></tbody></table><p>उदाहरण के लिए, 1.5 hour window, 20 files, 20 MB per file और 200 MB total के साथ, same IP से uploads तब block हो जाएँगे जब कोई भी configured limit cross हो जाए।</p><h2 id="file-types-exclude-करना" tabindex="-1">File Types Exclude करना <a class="header-anchor" href="#file-types-exclude-करना" aria-label="Permalink to &quot;File Types Exclude करना&quot;">​</a></h2><p><code>Excluded upload file types</code> regular users या visitors को selected file categories upload करने से रोकता है।</p><p>Available categories:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif जैसी image files</td></tr><tr><td>Videos</td><td>mp4, webm, mov जैसी video files</td></tr><tr><td>Audio</td><td>mp3, flac, wav जैसी audio files</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx जैसी document files</td></tr><tr><td>Other</td><td>ऊपर की categories से बाहर की files, जैसे zip, rar, exe, apk</td></tr></tbody></table><p>Default में कोई type selected नहीं होता, यानी वह allowed है।</p><p>किसी type पर click करने से वह highlight होता है, जिसका मतलब है कि वह type blocked है।</p><p>अगर <code>Other</code> selected है, तो zip या rar files upload करने वाले visitors block होंगे और उन्हें बताया जाएगा कि यह file type supported नहीं है।</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>Limit trigger होने पर users को matching message दिखता है:</p><p><img src="'+a+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Message Meaning</th></tr></thead><tbody><tr><td>Single file too large</td><td>File बहुत बड़ी है, upload से पहले compress करें।</td></tr><tr><td>File type blocked</td><td>यह file type supported नहीं है। इसे हटाएँ और फिर कोशिश करें।</td></tr><tr><td>Uploads too frequent</td><td>Recent uploads बहुत frequent हैं, retry time दिखेगा।</td></tr><tr><td>Total size too high</td><td>Recent total upload size बहुत अधिक है, retry time दिखेगा।</td></tr></tbody></table><h2 id="कब-enable-करें" tabindex="-1">कब Enable करें <a class="header-anchor" href="#कब-enable-करें" aria-label="Permalink to &quot;कब Enable करें&quot;">​</a></h2><p>अगर आपका upload homepage publicly accessible है, तो user rate limits enable करें।</p><p>Common reasons:</p><ul><li>आपको scripted bulk uploads की चिंता है।</li><li>आप बड़े visitor uploads limit करना चाहते हैं।</li><li>आप चाहते हैं कि regular users केवल images upload करें, archives या installers नहीं।</li><li>आप public upload को available रखना चाहते हैं, लेकिन resource usage control में रखना चाहते हैं।</li></ul><p>अगर site केवल आपके लिए है, या केवल administrators upload कर सकते हैं, तो इसे disabled छोड़ा जा सकता है।</p>',28)])])}const f=i(r,[["render",o]]);export{g as __pageData,f as default};
